input.addEventListener('input', (e) => search(e.target.value))

function throttle(fn, delay) {
  let lastCall = 0
  let timer = null

  return function (...args) {
    const remaining = delay - (Date.now() - lastCall)
    clearTimeout(timer)

    if (remaining <= 0) {
      fn.apply(this, args)
      lastCall = Date.now()
    } else {
      // trailing call — always fire with the latest args
      timer = setTimeout(() => {
        fn.apply(this, args)
        lastCall = Date.now()
      }, remaining)
    }
  }
}

