async function retry(fn, retries = 3, baseDelay = 100) {
  let attempt = 0
  let lastError

  while (attempt <= retries) {
    try {
      return await fn()
    } catch (err) {
      lastError = err
      if (attempt === retries) break

      const wait = baseDelay * 2 ** attempt // exponential backoff
      await sleep(wait)
      attempt++
    }
  }

  throw lastError
}

