const event = {
  user: { email: 'alice@example.com', authorization: 'Bearer abc.def.ghi' },
  message: 'login failed for alice@example.com',
}
console.log(redact(event))
// { user: { email: '[email]', authorization: '[redacted]' },
//   message: 'login failed for [email]' }

